const sqlite3 = require('sqlite3').verbose();
const path = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-revamp/orders.db';

return new Promise((resolve, reject) => {
  const db = new sqlite3.Database(path, (err) => {
    if (err) {
      resolve({ json: { ok: false, error: err.message, step: 'open' } });
      return;
    }

    db.get('SELECT COUNT(*) as count FROM orders', (err, row) => {
      if (err) {
        resolve({ json: { ok: false, error: err.message, step: 'count' } });
      } else {
        resolve({ json: { ok: true, count: row.count } });
      }
      db.close();
    });
  });
});
